package com.chaobo.scm.supplier.application.profile;

import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.infrastructure.persistence.profile.SupplierAdmissionQueryMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class SupplierAdmissionQueryApplicationService {private final SupplierAdmissionQueryMapper mapper;public SupplierAdmissionQueryApplicationService(SupplierAdmissionQueryMapper mapper){this.mapper=mapper;}@Transactional(readOnly=true)public PageResult<SupplierAdmissionView> page(Integer status,String keyword,int pageNo,int pageSize){check(pageNo,pageSize);return new PageResult<>(pageNo,pageSize,mapper.count(status,keyword),mapper.page(status,keyword,(pageNo-1)*pageSize,pageSize).stream().map(this::view).toList());}@Transactional(readOnly=true)public SupplierAdmissionView detail(long id){var row=mapper.find(id);if(row==null)throw new BusinessException(ErrorCode.NOT_FOUND,"准入申请不存在");return view(row);}private SupplierAdmissionView view(SupplierAdmissionQueryMapper.Row r){return new SupplierAdmissionView(r.id(),r.no(),r.code(),r.name(),r.taxNo(),r.type(),r.contact(),r.mobile(),r.settlement(),r.status(),r.reject(),r.version());}private static void check(int page,int size){if(page<1||size<1||size>100)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"分页参数不合法");}}
